(window.webpackJsonp=window.webpackJsonp||[]).push([[820],{806:function(s){s.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * Definition for a binary tree node.\\n * function TreeNode(val, left, right) {\\n *     this.val = (val===undefined ? 0 : val)\\n *     this.left = (left===undefined ? null : left)\\n *     this.right = (right===undefined ? null : right)\\n * }\\n */</span>\\n<span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{TreeNode}</span> <span class=\\"hljs-variable\\">root</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{number}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> pseudoPalindromicPaths  = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">root</span>) </span>{\\n  <span class=\\"hljs-keyword\\">if</span>(!root)<span class=\\"hljs-keyword\\">return</span> <span class=\\"hljs-number\\">0</span>\\n  <span class=\\"hljs-keyword\\">let</span> pathObj={\\n    [root.val]:<span class=\\"hljs-number\\">1</span>\\n  }\\n  <span class=\\"hljs-keyword\\">let</span> res=<span class=\\"hljs-number\\">0</span>\\n  dfs(root,pathObj)\\n  <span class=\\"hljs-keyword\\">return</span> res\\n  <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span> <span class=\\"hljs-title\\">dfs</span>(<span class=\\"hljs-params\\">root,pathObj</span>)</span>{\\n    <span class=\\"hljs-keyword\\">if</span>(root.left){\\n      <span class=\\"hljs-keyword\\">let</span> lVal=root.left.val\\n      <span class=\\"hljs-keyword\\">if</span>(!pathObj[lVal])pathObj[lVal]=<span class=\\"hljs-number\\">0</span>\\n      pathObj[lVal]++\\n      dfs(root.left,pathObj)\\n      pathObj[lVal]--\\n    }\\n    <span class=\\"hljs-keyword\\">if</span>(root.right){\\n      <span class=\\"hljs-keyword\\">let</span> rVal=root.right.val\\n      <span class=\\"hljs-keyword\\">if</span>(!pathObj[rVal])pathObj[rVal]=<span class=\\"hljs-number\\">0</span>\\n      pathObj[rVal]++\\n      dfs(root.right,pathObj)\\n      pathObj[rVal]--    \\n    }\\n    <span class=\\"hljs-keyword\\">if</span>(!root.left &amp;&amp; !root.right){\\n      <span class=\\"hljs-keyword\\">let</span> single=<span class=\\"hljs-number\\">0</span>\\n      <span class=\\"hljs-keyword\\">let</span> valid=<span class=\\"hljs-literal\\">true</span>\\n      <span class=\\"hljs-comment\\">// console.log(pathObj)</span>\\n      <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> k <span class=\\"hljs-keyword\\">in</span> pathObj){\\n        <span class=\\"hljs-keyword\\">if</span>(pathObj[k] % <span class=\\"hljs-number\\">2</span>===<span class=\\"hljs-number\\">1</span>){\\n          <span class=\\"hljs-keyword\\">if</span>(single&gt;<span class=\\"hljs-number\\">0</span>){\\n            valid=<span class=\\"hljs-literal\\">false</span>\\n            <span class=\\"hljs-keyword\\">break</span>\\n          }<span class=\\"hljs-keyword\\">else</span>{\\n            single=<span class=\\"hljs-number\\">1</span>\\n          }\\n        }\\n      }\\n      <span class=\\"hljs-keyword\\">if</span>(valid){\\n        res++\\n      }\\n    }\\n  }\\n};\\n</code></pre>\\n"],"titleSlug":"pseudo-palindromic-paths-in-a-binary-tree","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e00\u68f5\u4e8c\u53c9\u6811\uff0c\u6bcf\u4e2a\u8282\u70b9\u7684\u503c\u4e3a 1 \u5230 9 \u3002\u6211\u4eec\u79f0\u4e8c\u53c9\u6811\u4e2d\u7684\u4e00\u6761\u8def\u5f84\u662f \u300c<strong>\u4f2a\u56de\u6587</strong>\u300d\u7684\uff0c\u5f53\u5b83\u6ee1\u8db3\uff1a\u8def\u5f84\u7ecf\u8fc7\u7684\u6240\u6709\u8282\u70b9\u503c\u7684\u6392\u5217\u4e2d\uff0c\u5b58\u5728\u4e00\u4e2a\u56de\u6587\u5e8f\u5217\u3002</p>\\n\\n<p>\u8bf7\u4f60\u8fd4\u56de\u4ece\u6839\u5230\u53f6\u5b50\u8282\u70b9\u7684\u6240\u6709\u8def\u5f84\u4e2d&nbsp;<strong>\u4f2a\u56de\u6587&nbsp;</strong>\u8def\u5f84\u7684\u6570\u76ee\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<p><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2020/05/23/palindromic_paths_1.png\\" style=\\"height: 201px; width: 300px;\\"></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>root = [2,3,1,3,1,null,1]\\n<strong>\u8f93\u51fa\uff1a</strong>2 \\n<strong>\u89e3\u91ca\uff1a</strong>\u4e0a\u56fe\u4e3a\u7ed9\u5b9a\u7684\u4e8c\u53c9\u6811\u3002\u603b\u5171\u6709 3 \u6761\u4ece\u6839\u5230\u53f6\u5b50\u7684\u8def\u5f84\uff1a\u7ea2\u8272\u8def\u5f84 [2,3,3] \uff0c\u7eff\u8272\u8def\u5f84 [2,1,1] \u548c\u8def\u5f84 [2,3,1] \u3002\\n     \u5728\u8fd9\u4e9b\u8def\u5f84\u4e2d\uff0c\u53ea\u6709\u7ea2\u8272\u548c\u7eff\u8272\u7684\u8def\u5f84\u662f\u4f2a\u56de\u6587\u8def\u5f84\uff0c\u56e0\u4e3a\u7ea2\u8272\u8def\u5f84 [2,3,3] \u5b58\u5728\u56de\u6587\u6392\u5217 [3,2,3] \uff0c\u7eff\u8272\u8def\u5f84 [2,1,1] \u5b58\u5728\u56de\u6587\u6392\u5217 [1,2,1] \u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<p><strong><img alt=\\"\\" src=\\"https://assets.leetcode-cn.com/aliyun-lc-upload/uploads/2020/05/23/palindromic_paths_2.png\\" style=\\"height: 314px; width: 300px;\\"></strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>root = [2,1,1,1,3,null,null,null,null,null,1]\\n<strong>\u8f93\u51fa\uff1a</strong>1 \\n<strong>\u89e3\u91ca\uff1a</strong>\u4e0a\u56fe\u4e3a\u7ed9\u5b9a\u4e8c\u53c9\u6811\u3002\u603b\u5171\u6709 3 \u6761\u4ece\u6839\u5230\u53f6\u5b50\u7684\u8def\u5f84\uff1a\u7eff\u8272\u8def\u5f84 [2,1,1] \uff0c\u8def\u5f84 [2,1,3,1] \u548c\u8def\u5f84 [2,1] \u3002\\n     \u8fd9\u4e9b\u8def\u5f84\u4e2d\u53ea\u6709\u7eff\u8272\u8def\u5f84\u662f\u4f2a\u56de\u6587\u8def\u5f84\uff0c\u56e0\u4e3a [2,1,1] \u5b58\u5728\u56de\u6587\u6392\u5217 [1,2,1] \u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>root = [9]\\n<strong>\u8f93\u51fa\uff1a</strong>1\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li>\u7ed9\u5b9a\u4e8c\u53c9\u6811\u7684\u8282\u70b9\u6570\u76ee\u5728&nbsp;<code>1</code>&nbsp;\u5230&nbsp;<code>10^5</code>&nbsp;\u4e4b\u95f4\u3002</li>\\n\\t<li>\u8282\u70b9\u503c\u5728&nbsp;<code>1</code> \u5230&nbsp;<code>9</code>&nbsp;\u4e4b\u95f4\u3002</li>\\n</ul>\\n","title":"1457. \u4e8c\u53c9\u6811\u4e2d\u7684\u4f2a\u56de\u6587\u8def\u5f84","relatedTags":["\u4f4d\u8fd0\u7b97","\u6811","\u6df1\u5ea6\u4f18\u5148\u641c\u7d22"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1457"}')}}]);